const VERSION = __SNIPPET_VERSION__;
const STORAGE_KEY = 'hypotests:visitorId';
const COOKIE_NAME = 'hypotests_vid';
const ONE_YEAR_SECONDS = 60 * 60 * 24 * 365;
const DEFAULT_ASSIGN_ENDPOINT = '/api/v1/assign';
const DEFAULT_EVENT_ENDPOINT = '/api/v1/events';

function readGlobalConfig() {
  if (typeof window === 'undefined') {
    return {};
  }
  const scriptConfig = (() => {
    const currentScript = document.currentScript;
    if (!currentScript) {
      return {};
    }
    const dataset = currentScript.dataset || {};
    const config = {};
    if (dataset.apiBase) {
      config.apiBaseUrl = dataset.apiBase;
    }
    if (dataset.experimentKey) {
      config.experimentKey = dataset.experimentKey;
    }
    if (dataset.platform) {
      config.platform = dataset.platform;
    }
    if (dataset.region) {
      config.region = dataset.region;
    }
    if (dataset.debug) {
      config.debug = dataset.debug === 'true';
    }
    return config;
  })();

  const globalConfig = window.hypotestsConfig || window.__hypotestsConfig || {};
  return {
    apiBaseUrl: 'http://localhost:8080',
    assignEndpoint: DEFAULT_ASSIGN_ENDPOINT,
    eventEndpoint: DEFAULT_EVENT_ENDPOINT,
    debug: false,
    variants: {},
    ...globalConfig,
    ...scriptConfig,
  };
}

function log(config, ...args) {
  if (config.debug && typeof console !== 'undefined') {
    console.log('[Hypotests]', ...args);
  }
}

function warn(config, ...args) {
  if (typeof console !== 'undefined' && console.warn) {
    console.warn('[Hypotests]', ...args);
  }
}

function getFromCookie(name) {
  if (typeof document === 'undefined') {
    return null;
  }
  const match = document.cookie.match(new RegExp('(?:^|; )' + name.replace(/([.$?*|{}()\[\]\\/+^])/g, '\\$1') + '=([^;]*)'));
  return match ? decodeURIComponent(match[1]) : null;
}

function setCookie(name, value) {
  if (typeof document === 'undefined') {
    return;
  }
  const expires = new Date(Date.now() + ONE_YEAR_SECONDS * 1000);
  document.cookie = `${name}=${encodeURIComponent(value)}; path=/; expires=${expires.toUTCString()}; SameSite=Lax`;
}

function getFromStorage(key) {
  if (typeof window === 'undefined') {
    return null;
  }
  try {
    return window.localStorage.getItem(key);
  } catch (error) {
    return null;
  }
}

function setStorage(key, value) {
  if (typeof window === 'undefined') {
    return;
  }
  try {
    window.localStorage.setItem(key, value);
  } catch (error) {
    // Ignore storage failures (e.g., Safari private mode)
  }
}

function generateVisitorId() {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  const random = Math.random().toString(16).slice(2);
  const timestamp = Date.now().toString(16);
  return `${timestamp}-${random}`;
}

function getVisitorId() {
  const fromStorage = getFromStorage(STORAGE_KEY);
  if (fromStorage) {
    return fromStorage;
  }
  const fromCookie = getFromCookie(COOKIE_NAME);
  if (fromCookie) {
    setStorage(STORAGE_KEY, fromCookie);
    return fromCookie;
  }
  const newId = generateVisitorId();
  setStorage(STORAGE_KEY, newId);
  setCookie(COOKIE_NAME, newId);
  return newId;
}

function detectPlatform() {
  if (typeof navigator === 'undefined') {
    return undefined;
  }
  const ua = navigator.userAgent || '';
  return /Mobi|Android/i.test(ua) ? 'mobile' : 'desktop';
}

function makeUrl(base, endpoint) {
  if (!base) {
    return endpoint;
  }
  const hasTrailingSlash = base.endsWith('/');
  const hasLeadingSlash = endpoint.startsWith('/');
  if (hasTrailingSlash && hasLeadingSlash) {
    return base + endpoint.slice(1);
  }
  if (!hasTrailingSlash && !hasLeadingSlash) {
    return `${base}/${endpoint}`;
  }
  return base + endpoint;
}

async function assignVariant(config, visitorId, platform, region) {
  const url = makeUrl(config.apiBaseUrl, config.assignEndpoint || DEFAULT_ASSIGN_ENDPOINT);
  const payload = {
    experimentKey: config.experimentKey,
    visitorId,
    platform,
    region,
  };
  log(config, 'Request assignment', payload, url);
  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    keepalive: true,
    body: JSON.stringify(payload),
  });
  if (!response.ok) {
    throw new Error(`Assignment failed with status ${response.status}`);
  }
  const body = await response.json();
  log(config, 'Received assignment', body);
  return body;
}

function sendEvent(config, assignment, visitorId, eventType, extra = {}) {
  const url = makeUrl(config.apiBaseUrl, config.eventEndpoint || DEFAULT_EVENT_ENDPOINT);
  const payload = {
    experimentKey: assignment.experimentKey,
    variantKey: assignment.variantKey,
    visitorId,
    eventType,
    userAgent: typeof navigator !== 'undefined' ? navigator.userAgent : undefined,
    region: config.region,
    createdAt: new Date().toISOString(),
    ...extra,
  };
  const data = JSON.stringify(payload);
  log(config, 'Send event', payload, url);
  if (typeof navigator !== 'undefined' && navigator.sendBeacon) {
    try {
      const blob = new Blob([data], { type: 'application/json' });
      navigator.sendBeacon(url, blob);
      return;
    } catch (error) {
      warn(config, 'sendBeacon failed, fallback to fetch', error);
    }
  }
  fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    keepalive: true,
    body: data,
  }).catch(error => warn(config, 'Fetch event failed', error));
}

function applyActions(config, actions, variantKey) {
  if (!Array.isArray(actions)) {
    return;
  }
  actions.forEach(action => {
    if (!action || !action.selector) {
      return;
    }
    const element = document.querySelector(action.selector);
    if (!element) {
      return;
    }
    switch (action.type) {
      case 'text':
        element.textContent = action.value;
        break;
      case 'html':
        element.innerHTML = action.value;
        break;
      case 'attribute':
        if (action.name) {
          element.setAttribute(action.name, action.value);
        }
        break;
      case 'style':
        if (action.property) {
          element.style[action.property] = action.value;
        }
        break;
      case 'class:add':
        if (action.value) {
          element.classList.add(action.value);
        }
        break;
      case 'class:remove':
        if (action.value) {
          element.classList.remove(action.value);
        }
        break;
      default:
        warn(config, 'Unknown action type', action, variantKey);
    }
  });
}

function setupClickTracking(selectors, handler) {
  if (!Array.isArray(selectors)) {
    return [];
  }
  const detach = [];
  selectors.forEach(selector => {
    const element = document.querySelector(selector);
    if (!element) {
      return;
    }
    const listener = event => handler(event, selector);
    element.addEventListener('click', listener);
    detach.push(() => element.removeEventListener('click', listener));
  });
  return detach;
}

function ready(fn) {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', fn, { once: true });
  } else {
    fn();
  }
}

function detectRegion(config) {
  if (config.region) {
    return config.region;
  }
  if (typeof document !== 'undefined') {
    const meta = document.querySelector('meta[name="hypotests-region"]');
    if (meta && meta.content) {
      return meta.content;
    }
  }
  return undefined;
}

function bootstrap() {
  const config = readGlobalConfig();
  if (!config.experimentKey) {
    warn(config, 'experimentKey is not configured');
    return;
  }
  const visitorId = getVisitorId();
  const platform = config.platform || detectPlatform();
  const region = detectRegion(config);
  config.platform = platform;
  if (region) {
    config.region = region;
  }
  const state = {
    assignment: null,
    clickDetach: [],
  };

  function exposeAPI() {
    const api = window.hypotests || {};
    api.version = VERSION;
    api.visitorId = visitorId;
    api.assignment = state.assignment;
    api.trackConversion = function trackConversion(extra = {}) {
      if (!state.assignment) {
        warn(config, 'Conversion ignored, no assignment yet');
        return;
      }
      sendEvent(config, state.assignment, visitorId, 'CONVERSION', extra);
    };
    api.resetAssignment = async function resetAssignment() {
      try {
        state.assignment = await assignVariant(config, visitorId, platform, region);
        applyVariantChanges();
      } catch (error) {
        warn(config, 'Failed to reassign variant', error);
      }
    };
    window.hypotests = api;
  }

  function applyVariantChanges() {
    ready(() => {
      if (!state.assignment) {
        return;
      }
      const variantConfig = config.variants && config.variants[state.assignment.variantKey];
      if (!variantConfig) {
        log(config, 'No variant config found for', state.assignment.variantKey);
        return;
      }
      if (state.clickDetach.length) {
        state.clickDetach.forEach(fn => fn());
        state.clickDetach = [];
      }
      applyActions(config, variantConfig.actions, state.assignment.variantKey);
      if (Array.isArray(variantConfig.trackClicks)) {
        state.clickDetach = setupClickTracking(variantConfig.trackClicks, () => {
          sendEvent(config, state.assignment, visitorId, 'CLICK');
        });
      }
      if (typeof variantConfig.onApplied === 'function') {
        try {
          variantConfig.onApplied(state.assignment, config, visitorId);
        } catch (error) {
          warn(config, 'Variant onApplied threw an error', error);
        }
      }
    });
  }

  assignVariant(config, visitorId, platform, region)
    .then(assignment => {
      state.assignment = assignment;
      exposeAPI();
      if (typeof window !== 'undefined' && Array.isArray(window.dataLayer)) {
        window.dataLayer.push({
          event: 'hypotests_assignment',
          experimentKey: assignment.experimentKey,
          variantKey: assignment.variantKey,
        });
      }
      applyVariantChanges();
      sendEvent(config, assignment, visitorId, 'IMPRESSION');
    })
    .catch(error => {
      warn(config, 'Failed to assign variant', error);
      exposeAPI();
    });
}

bootstrap();
